SELECT artifacts.artifact_id, artifacts.label, images.image_id, POW(artifacts.artifact_id, images.image_id) AS power_calculation
FROM artifacts
INNER JOIN images ON artifacts.artifact_id = images.artifact_id;

SELECT art.artifact_id, art.label, col.collection_id, col.collection_name 
FROM artifacts art 
JOIN collections col ON art.artifact_id = col.artifact_id;

SELECT collections.collection_id, COUNT(DISTINCT collections.artifact_id) AS num_artifacts
FROM collections
GROUP BY collections.collection_id;
